import{_ as o,o as s,c as t,ai as a}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"Agent Runtime","description":"","frontmatter":{"summary":"Agent runtime (embedded pi-mono), workspace contract, and session bootstrap","read_when":["Changing agent runtime, workspace bootstrap, or session behavior"],"title":"Agent Runtime"},"headers":[],"relativePath":"concepts/agent.md","filePath":"concepts/agent.md","lastUpdated":null}'),n={name:"concepts/agent.md"};function i(r,e,d,l,c,p){return s(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="agent-runtime-🤖" tabindex="-1"><a class="header-anchor" href="#agent-runtime-🤖">#</a> Agent Runtime 🤖</h1><p>OpenSoul runs a single embedded agent runtime derived from <strong>pi-mono</strong>.</p><h2 id="workspace-required" tabindex="-1"><a class="header-anchor" href="#workspace-required">#</a> Workspace (required)</h2><p>OpenSoul uses a single agent workspace directory (<code>agents.defaults.workspace</code>) as the agent’s <strong>only</strong> working directory (<code>cwd</code>) for tools and context.</p><p>Recommended: use <code>opensoul setup</code> to create <code>~/.opensoul/opensoul.json</code> if missing and initialize the workspace files.</p><p>Full workspace layout + backup guide: <a href="/docs/concepts/agent-workspace">Agent workspace</a></p><p>If <code>agents.defaults.sandbox</code> is enabled, non-main sessions can override this with per-session workspaces under <code>agents.defaults.sandbox.workspaceRoot</code> (see <a href="/docs/gateway/configuration">Gateway configuration</a>).</p><h2 id="bootstrap-files-injected" tabindex="-1"><a class="header-anchor" href="#bootstrap-files-injected">#</a> Bootstrap files (injected)</h2><p>Inside <code>agents.defaults.workspace</code>, OpenSoul expects these user-editable files:</p><ul><li><code>AGENTS.md</code> — operating instructions + “memory”</li><li><code>SOUL.md</code> — persona, boundaries, tone</li><li><code>TOOLS.md</code> — user-maintained tool notes (e.g. <code>imsg</code>, <code>sag</code>, conventions)</li><li><code>BOOTSTRAP.md</code> — one-time first-run ritual (deleted after completion)</li><li><code>IDENTITY.md</code> — agent name/vibe/emoji</li><li><code>USER.md</code> — user profile + preferred address</li></ul><p>On the first turn of a new session, OpenSoul injects the contents of these files directly into the agent context.</p><p>Blank files are skipped. Large files are trimmed and truncated with a marker so prompts stay lean (read the file for full content).</p><p>If a file is missing, OpenSoul injects a single “missing file” marker line (and <code>opensoul setup</code> will create a safe default template).</p><p><code>BOOTSTRAP.md</code> is only created for a <strong>brand new workspace</strong> (no other bootstrap files present). If you delete it after completing the ritual, it should not be recreated on later restarts.</p><p>To disable bootstrap file creation entirely (for pre-seeded workspaces), set:</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">agent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skipBootstrap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="built-in-tools" tabindex="-1"><a class="header-anchor" href="#built-in-tools">#</a> Built-in tools</h2><p>Core tools (read/exec/edit/write and related system tools) are always available, subject to tool policy. <code>apply_patch</code> is optional and gated by <code>tools.exec.applyPatch</code>. <code>TOOLS.md</code> does <strong>not</strong> control which tools exist; it’s guidance for how <em>you</em> want them used.</p><h2 id="skills" tabindex="-1"><a class="header-anchor" href="#skills">#</a> Skills</h2><p>OpenSoul loads skills from three locations (workspace wins on name conflict):</p><ul><li>Bundled (shipped with the install)</li><li>Managed/local: <code>~/.opensoul/skills</code></li><li>Workspace: <code>&lt;workspace&gt;/skills</code></li></ul><p>Skills can be gated by config/env (see <code>skills</code> in <a href="/docs/gateway/configuration">Gateway configuration</a>).</p><h2 id="pi-mono-integration" tabindex="-1"><a class="header-anchor" href="#pi-mono-integration">#</a> pi-mono integration</h2><p>OpenSoul reuses pieces of the pi-mono codebase (models/tools), but <strong>session management, discovery, and tool wiring are OpenSoul-owned</strong>.</p><ul><li>No pi-coding agent runtime.</li><li>No <code>~/.pi/agent</code> or <code>&lt;workspace&gt;/.pi</code> settings are consulted.</li></ul><h2 id="sessions" tabindex="-1"><a class="header-anchor" href="#sessions">#</a> Sessions</h2><p>Session transcripts are stored as JSONL at:</p><ul><li><code>~/.opensoul/agents/&lt;agentId&gt;/sessions/&lt;SessionId&gt;.jsonl</code></li></ul><p>The session ID is stable and chosen by OpenSoul. Legacy Pi/Tau session folders are <strong>not</strong> read.</p><h2 id="steering-while-streaming" tabindex="-1"><a class="header-anchor" href="#steering-while-streaming">#</a> Steering while streaming</h2><p>When queue mode is <code>steer</code>, inbound messages are injected into the current run. The queue is checked <strong>after each tool call</strong>; if a queued message is present, remaining tool calls from the current assistant message are skipped (error tool results with &quot;Skipped due to queued user message.&quot;), then the queued user message is injected before the next assistant response.</p><p>When queue mode is <code>followup</code> or <code>collect</code>, inbound messages are held until the current turn ends, then a new agent turn starts with the queued payloads. See <a href="/docs/concepts/queue">Queue</a> for mode + debounce/cap behavior.</p><p>Block streaming sends completed assistant blocks as soon as they finish; it is <strong>off by default</strong> (<code>agents.defaults.blockStreamingDefault: &quot;off&quot;</code>). Tune the boundary via <code>agents.defaults.blockStreamingBreak</code> (<code>text_end</code> vs <code>message_end</code>; defaults to text_end). Control soft block chunking with <code>agents.defaults.blockStreamingChunk</code> (defaults to 800–1200 chars; prefers paragraph breaks, then newlines; sentences last). Coalesce streamed chunks with <code>agents.defaults.blockStreamingCoalesce</code> to reduce single-line spam (idle-based merging before send). Non-Telegram channels require explicit <code>*.blockStreaming: true</code> to enable block replies. Verbose tool summaries are emitted at tool start (no debounce); Control UI streams tool output via agent events when available. More details: <a href="/docs/concepts/streaming">Streaming + chunking</a>.</p><h2 id="model-refs" tabindex="-1"><a class="header-anchor" href="#model-refs">#</a> Model refs</h2><p>Model refs in config (for example <code>agents.defaults.model</code> and <code>agents.defaults.models</code>) are parsed by splitting on the <strong>first</strong> <code>/</code>.</p><ul><li>Use <code>provider/model</code> when configuring models.</li><li>If the model ID itself contains <code>/</code> (OpenRouter-style), include the provider prefix (example: <code>openrouter/moonshotai/kimi-k2</code>).</li><li>If you omit the provider, OpenSoul treats the input as an alias or a model for the <strong>default provider</strong> (only works when there is no <code>/</code> in the model ID).</li></ul><h2 id="configuration-minimal" tabindex="-1"><a class="header-anchor" href="#configuration-minimal">#</a> Configuration (minimal)</h2><p>At minimum, set:</p><ul><li><code>agents.defaults.workspace</code></li><li><code>channels.whatsapp.allowFrom</code> (strongly recommended)</li></ul><hr><p><em>Next: <a href="/docs/channels/group-messages">Group Chats</a></em> 🦞</p>',41)])])}const g=o(n,[["render",i]]);export{h as __pageData,g as default};
